// src/components/ListaPacientes.jsx
import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { Pencil, Trash2 } from 'lucide-react';

function ListaPacientes({ reloadKey, onEditar }) {
  const [pacientes, setPacientes] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [isAluno, setIsAluno] = useState(false);
  const [searchTerm, setSearchTerm] = useState('');
  const [pagina, setPagina] = useState(1);

  const POR_PAGINA = 100;

  // Detecta se o usuário logado é aluno
  useEffect(() => {
    try {
      const userStr = localStorage.getItem('user');
      if (userStr) {
        const user = JSON.parse(userStr);
        if (user && user.role && user.role.toLowerCase() === 'aluno') {
          setIsAluno(true);
        }
      }
    } catch {
      setIsAluno(false);
    }
  }, []);

  // Carrega pacientes
  useEffect(() => {
    setCarregando(true);
    axios.get('/api/pacientes')
      .then(res => {
        setPacientes(res.data);
        setCarregando(false);
      })
      .catch(() => setCarregando(false));
  }, [reloadKey]);

  // Sempre volta para a página 1 ao buscar
  useEffect(() => { setPagina(1); }, [searchTerm, pacientes.length]);

  const handleDeletar = (id) => {
    if (window.confirm('Deletar este paciente?')) {
      axios.delete(`/api/pacientes/${id}`)
        .then(() => setPacientes(prev => prev.filter(p => p.id !== id)));
    }
  };

  // Filtra resultados conforme pesquisa
  const filteredPacientes = pacientes.filter(p => {
    const term = searchTerm.toLowerCase();
    const pront = (p.numero_prontuario ? p.numero_prontuario.toString().toLowerCase() : '');
    const nome = (p.nome || '').toLowerCase();
    const telefone = (p.telefone || '');
    return pront.includes(term)
      || nome.includes(term)
      || telefone.includes(term);
  });

  // Paginação
  const totalPaginas = Math.ceil(filteredPacientes.length / POR_PAGINA);
  const inicio = (pagina - 1) * POR_PAGINA;
  const fim = inicio + POR_PAGINA;
  const pacientesPagina = filteredPacientes.slice(inicio, fim);

  if (carregando) return <p>Carregando pacientes...</p>;
  if (pacientes.length === 0) return <p>Nenhum paciente cadastrado.</p>;

  return (
    <div className="mx-auto py-2 px-2">
      <div className="bg-white rounded-2xl p-2">
        {/* Campo de Pesquisa */}
        <div className="mb-4">
          <input
            type="text"
            placeholder="Pesquisar por prontuário, nome ou telefone"
            value={searchTerm}
            onChange={e => setSearchTerm(e.target.value)}
            className="w-full border rounded px-3 py-2"
          />
        </div>
        {/* Paginação */}
        <div className="flex justify-between items-center mb-4">
          <button
            onClick={() => setPagina(p => Math.max(1, p - 1))}
            disabled={pagina === 1}
            className="text-blue-600 hover:underline rounded disabled:opacity-50"
          >
            Anterior
          </button>
          <span>
            Página {pagina} de {totalPaginas} &nbsp;
            <small>({filteredPacientes.length} pacientes)</small>
          </span>
          <button
            onClick={() => setPagina(p => Math.min(totalPaginas, p + 1))}
            disabled={pagina === totalPaginas}
            className="text-blue-600 hover:underline rounded disabled:opacity-50"
          >
            Próxima
          </button>
        </div>
        {/* Lista responsiva */}
        <div className="space-y-0">
          {pacientesPagina.map((p, idx) => (
            <React.Fragment key={p.id}>
              <div className="flex flex-col md:flex-row md:items-center md:gap-4 bg-gray-50 rounded-xl px-4 py-3 shadow-sm hover:bg-gray-100 transition">
                {/* Ordem */}
                <div className="font-semibold text-gray-400 w-8 hidden md:block">{(inicio + idx + 1)}</div>
                {/* Prontuário */}
                <div className="mb-1 md:mb-0 w-full md:w-28">
                  <strong className="md:hidden">Prontuário: </strong>
                  <span className="text-gray-500">{p.numero_prontuario || '-'}</span>
                </div>
                {/* Nome */}
                <div className="mb-1 md:mb-0 w-full md:w-52">
                  <strong className="md:hidden">Nome: </strong>
                  <span className="font-medium text-gray-800">{p.nome}</span>
                </div>
                {/* Telefone */}
                <div className="mb-1 md:mb-0 w-full md:w-32">
                  <strong className="md:hidden">Telefone: </strong>
                  <span className="text-gray-500">{p.telefone}</span>
                </div>
                {/* Gaveta */}
                <div className="mb-1 md:mb-0 w-full md:w-20">
                  <strong className="md:hidden">N° Gaveta: </strong>
                  <span className="text-gray-500">{p.numero_gaveta || '-'}</span>
                </div>
                {/* CPF */}
                <div className="mb-1 md:mb-0 w-full md:w-32">
                  <strong className="md:hidden">CPF: </strong>
                  <span className="text-gray-500">{p.cpf || '-'}</span>
                </div>
                {/* Cidade */}
                <div className="mb-2 md:mb-0 w-full md:w-32">
                  <strong className="md:hidden">Cidade: </strong>
                  <span className="text-gray-500">{p.cidade || '-'}</span>
                </div>
                {/* Ações */}
                <div className="flex flex-row justify-end gap-2 w-full md:w-auto mt-1 md:mt-0">
                  <button
                    onClick={() => onEditar(p)}
                    className="p-2 rounded-full bg-blue-100 text-blue-800 hover:bg-blue-200"
                    title="Editar paciente"
                  >
                    <Pencil size={18} />
                  </button>
                  {!isAluno && (
                    <button
                      onClick={() => handleDeletar(p.id)}
                      className="p-2 rounded-full bg-red-100 text-red-700 hover:bg-red-200"
                      title="Deletar paciente"
                    >
                      <Trash2 size={18} />
                    </button>
                  )}
                </div>
              </div>
              {/* SEPARADOR HORIZONTAL APENAS DESKTOP */}
              {idx !== pacientesPagina.length - 1 && (
                <hr className="hidden md:block border-t border-gray-200 mx-2 my-0" />
              )}
            </React.Fragment>
          ))}
        </div>
        {/* Paginação (embaixo) */}
        <div className="flex justify-between items-center my-4">
          <button
            onClick={() => setPagina(p => Math.max(1, p - 1))}
            disabled={pagina === 1}
            className="text-blue-600 hover:underline rounded disabled:opacity-50"
          >
            Anterior
          </button>
          <span>
            Página {pagina} de {totalPaginas}
          </span>
          <button
            onClick={() => setPagina(p => Math.min(totalPaginas, p + 1))}
            disabled={pagina === totalPaginas}
            className="text-blue-600 hover:underline rounded disabled:opacity-50"
          >
            Próxima
          </button>
        </div>
      </div>
    </div>
  );
}

export default ListaPacientes;
